parameters.content:
/**
 * Analytics service — aggregates order and user data into dashboard metrics.
 *
 * Depends on:
 * - OrderRepository (data layer) for order data
 * - UserRepository (data layer) for user data
 *
 * Architecture notes:
 * - This service is read-only; it queries existing data and computes aggregations.
 * - Methods return typed analytics models (see src/models/analytics.ts).
 * - Each public method corresponds to one logical API endpoint (see DESIGN.md).
 * - The service does NOT cache results. A future enhancement could add
 *   a caching layer or materialized views for performance.
 */

import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type { Order } from '../models/order.js';
import type {
  AnalyticsQuery,
  DashboardData,
  MetricQuery,
  MetricSummary,
  MetricType,
  OrderStatusBreakdown,
  TimeGranularity,
  TimeSeriesData,
  TimeSeriesPoint,
  TopEntity,
} from '../models/analytics.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get the full dashboard payload (all widgets in one call).
   */
  getDashboard(query: AnalyticsQuery): DashboardData {
    this.logger.info(`Generating dashboard for ${query.startDate} to ${query.endDate}`);

    const granularity = query.granularity ?? 'day';
    const metricQuery = (metric: MetricType): MetricQuery => ({
      metric,
      startDate: query.startDate,
      endDate: query.endDate,
      granularity,
      userId: query.userId,
    });

    return {
      metrics: [
        this.getMetricSummary(metricQuery('revenue')),
        this.getMetricSummary(metricQuery('orders')),
        this.getMetricSummary(metricQuery('users')),
        this.getMetricSummary(metricQuery('average-order-value')),
      ],
      revenueTimeSeries: this.getTimeSeries(metricQuery('revenue')),
      ordersTimeSeries: this.getTimeSeries(metricQuery('orders')),
      ordersByStatus: this.getOrdersByStatus(),
      topCustomers: this.getTopCustomers(),
      generatedAt: new Date().toISOString(),
    };
  }

  /**
   * Get a single metric's summary (current vs previous period).
   */
  getMetricSummary(query: MetricQuery): MetricSummary {
    this.logger.info(`Computing metric summary: ${query.metric}`);

    const start = new Date(query.startDate);
    const end = new Date(query.endDate);
    const durationMs = end.getTime() - start.getTime();
    const prevStart = new Date(start.getTime() - durationMs);
    const prevEnd = new Date(start.getTime());

    const currentOrders = this.getOrdersInRange(start, end, query.userId);
    const previousOrders = this.getOrdersInRange(prevStart, prevEnd, query.userId);

    const currentValue = this.computeMetricValue(query.metric, currentOrders, start, end, query.userId);
    const previousValue = this.computeMetricValue(query.metric, previousOrders, prevStart, prevEnd, query.userId);

    const changePercent = previousValue === 0
      ? (currentValue === 0 ? 0 : 100)
      : ((currentValue - previousValue) / previousValue) * 100;

    return {
      metric: query.metric,
      currentValue,
      previousValue,
      changePercent,
    };
  }

  /**
   * Get time-series data for a specific metric.
   */
  getTimeSeries(query: MetricQuery): TimeSeriesData {
    const granularity = query.granularity ?? 'day';
    this.logger.info(`Computing time series: ${query.metric}, granularity: ${granularity}`);

    const start = new Date(query.startDate);
    const end = new Date(query.endDate);
    const buckets = this.generateBuckets(start, end, granularity);
    const orders = this.getOrdersInRange(start, end, query.userId);

    const points: TimeSeriesPoint[] = buckets.map((bucketStart, i) => {
      const bucketEnd = i < buckets.length - 1 ? buckets[i + 1] : end;
      const bucketOrders = orders.filter(
        (o) => o.createdAt >= bucketStart && o.createdAt < bucketEnd,
      );
      const value = this.computeMetricValue(query.metric, bucketOrders, bucketStart, bucketEnd, query.userId);
      return { timestamp: bucketStart.toISOString(), value };
    });

    return {
      metric: query.metric,
      granularity,
      start: query.startDate,
      end: query.endDate,
      points,
    };
  }

  /**
   * Get order counts and totals broken down by status.
   * No date filtering — shows current state of all orders.
   */
  getOrdersByStatus(): OrderStatusBreakdown[] {
    this.logger.info('Computing order status breakdown');

    const allOrders = this.orderRepository.findAll();
    const statusMap = new Map<string, { count: number; total: number }>();

    const statuses: Array<Order['status']> = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
    for (const s of statuses) {
      statusMap.set(s, { count: 0, total: 0 });
    }

    for (const order of allOrders) {
      const entry = statusMap.get(order.status);
      if (entry) {
        entry.count += 1;
        entry.total += order.total;
      }
    }

    return statuses.map((status) => {
      const entry = statusMap.get(status)!;
      return { status, count: entry.count, total: entry.total };
    });
  }

  /**
   * Get top customers ranked by total revenue.
   */
  getTopCustomers(limit: number = 10): TopEntity[] {
    this.logger.info(`Computing top ${limit} customers`);

    const allOrders = this.orderRepository.findAll();
    const revenueByUser = new Map<string, number>();

    for (const order of allOrders) {
      revenueByUser.set(order.userId, (revenueByUser.get(order.userId) ?? 0) + order.total);
    }

    const sorted = Array.from(revenueByUser.entries()).sort((a, b) => b[1] - a[1]);
    const topEntries = sorted.slice(0, limit);

    return topEntries.map(([userId, value]) => {
      const user = this.userRepository.findById(userId);
      return {
        id: userId,
        name: user?.name ?? 'Unknown',
        value,
      };
    });
  }

  // ── Private helpers ──

  private getOrdersInRange(start: Date, end: Date, userId?: string): Order[] {
    return this.orderRepository.findAll((order) => {
      if (order.createdAt < start || order.createdAt >= end) return false;
      if (userId && order.userId !== userId) return false;
      return true;
    });
  }

  private computeMetricValue(
    metric: MetricType,
    orders: Order[],
    start: Date,
    end: Date,
    userId?: string,
  ): number {
    switch (metric) {
      case 'revenue':
        return orders.reduce((sum, o) => sum + o.total, 0);
      case 'orders':
        return orders.length;
      case 'users': {
        const users = this.userRepository.findAll(
          (u) => u.createdAt >= start && u.createdAt < end && (!userId || u.id === userId),
        );
        return users.length;
      }
      case 'average-order-value':
        return orders.length === 0 ? 0 : orders.reduce((sum, o) => sum + o.total, 0) / orders.length;
    }
  }

  private generateBuckets(start: Date, end: Date, granularity: TimeGranularity): Date[] {
    const buckets: Date[] = [];
    let current = new Date(start);

    while (current < end) {
      buckets.push(new Date(current));
      switch (granularity) {
        case 'hour':
          current = new Date(current.getTime() + 60 * 60 * 1000);
          break;
        case 'day':
          current = new Date(current.getTime() + 24 * 60 * 60 * 1000);
          break;
        case 'week':
          current = new Date(current.getTime() + 7 * 24 * 60 * 60 * 1000);
          break;
        case 'month': {
          const next = new Date(current);
          next.setMonth(next.getMonth() + 1);
          current = next;
          break;
        }
      }
    }

    return buckets;
  }
}

